123	// 128x128, mma2x4, warp4x4(64,32,16), stages, block swizzle, dsmem
124	template <const int MMA_M = 16, const int MMA_N = 8, const int MMA_K = 16,
125	          const int MMA_TILE_M = 2, const int MMA_TILE_N = 4,
126	          const int WARP_TILE_M = 4, const int WARP_TILE_N = 4,
127	          const int A_PAD = 0, const int B_PAD = 0, const int K_STAGE = 2,
128	          const bool BLOCK_SWIZZLE = false>
129	__global__ void __launch_bounds__(256)
130	    hgemm_mma_m16n8k16_mma2x4_warp4x4_stages_dsmem_tn_kernel(half *A, half *B,
131	                                                             half *C, int M,
132	                                                             int N, int K) {
133	  // BLOCK_SWIZZLE 0/1 control use block swizzle or not.
134	  const int bx = ((int)BLOCK_SWIZZLE) * blockIdx.z * gridDim.x + blockIdx.x;
135	  const int by = blockIdx.y;
136	  const int NUM_K_TILES = div_ceil(K, MMA_K);
137	  constexpr int BM = MMA_M * MMA_TILE_M * WARP_TILE_M; // 16*2*4=128
138	  constexpr int BN = MMA_N * MMA_TILE_N * WARP_TILE_N; // 8*4*4=128
139	  constexpr int BK = MMA_K;                            // 16
140	
141	  extern __shared__ half smem[];
142	  half *s_a = smem;
143	  half *s_b = smem + K_STAGE * BM * (BK + A_PAD);
144	  constexpr int s_a_stage_offset = BM * (BK + A_PAD); // BMxBK 128*16
145	  constexpr int s_b_stage_offset = BN * (BK + B_PAD); // BNxBK 128*16
146	
147	  const int tid = threadIdx.y * blockDim.x + threadIdx.x; // within block
148	  const int warp_id = tid / WARP_SIZE; // 0~7 warp_id within block
149	  const int lane_id = tid % WARP_SIZE; // 0~31
150	  const int warp_m = warp_id % 2;      // 0,1
151	  const int warp_n = warp_id / 2;      // 0,1,2,3
152	
153	  int load_smem_a_m = tid / 2;                 // row 0~127
154	  int load_smem_a_k = (tid % 2 == 0) ? 0 : 8;  // col 0,8
155	  int load_smem_b_n = tid / 2;                 // row 0~127
156	  int load_smem_b_k = (tid % 2 == 0) ? 0 : 8;  // col 0,8
